mapper.select:
SELECT * FROM product

    deleted = 0

        AND title LIKE CONCAT('%', #{dto.keyword}, '%')


        AND platform = #{dto.platform}


        AND category = #{dto.category}


        AND price >= #{dto.minPrice}


        AND price <= #{dto.maxPrice}


        AND rating >= #{dto.minRating}


        AND collect_date >= #{dto.startDate}


        AND collect_date <= #{dto.endDate}


        AND verdict = #{dto.verdict}




        ORDER BY sales ASCDESC


        ORDER BY rating ASCDESC


        ORDER BY ai_score ASCDESC


        ORDER BY create_time DESC

SELECT * FROM product
WHERE deleted = 0 AND ai_score IS NOT NULL

    AND platform = #{platform}

ORDER BY ai_score DESC
LIMIT #{limit}

SELECT p.category, DATE(p.create_time) AS statDate, COUNT(p.id) AS productCount, AVG(p.ai_score) AS avgAiScore, AVG(p.sales) AS avgSales FROM product p WHERE p.deleted = 0 AND p.category IS NOT NULL AND p.create_time >= DATE_SUB(CURDATE(), INTERVAL #{days} DAY)
AND p.category = #{category}
GROUP BY p.category, DATE(p.create_time) ORDER BY statDate ASC
